+        std::fs::write(&zero_path, b"").unwrap();
+
+        let file = std::fs::File::open(&zero_path).unwrap();
+        let result = zip::ZipArchive::new(file);
+        assert!(result.is_err(), "zero-byte file is not a valid zip");
